    @Test
    @DisplayName("wrap() propagates IORuntimeException when reader.close() throws IOException")
    public void test_TC15() throws Exception {
        // Create Reader that returns -1 on read, and throws IOException on close to hit close(reader) catch
        Reader faulty = new Reader() {
            @Override
            public int read(char[] cbuf, int off, int len) {
                return -1; // EOF immediately
            }
            @Override
            public void close() throws IOException {
                throw new IOException("close-fail");
            }
        };
        // Use reflection to call package-private from(Reader, boolean)
        Method m = WordWrap.class.getDeclaredMethod("from", Reader.class, boolean.class);
        m.setAccessible(true);
        WordWrap.Builder builder = (WordWrap.Builder) m.invoke(null, faulty, true);
        StringWriter out = new StringWriter();
        // wrap(Writer) should propagate IORuntimeException on close
        Exception ex = assertThrows(RuntimeException.class, () -> builder.wrap(out));
        // Ensure cause message contains "close-fail"
        assertTrue(ex.getCause() instanceof IOException);
        assertEquals("close-fail", ex.getCause().getMessage());
    }

